-- Menja Fresh — Zucchini Noodle "Spaghetti" with Pesto, Tomatoes & Feta
-- (vegetarian, protein-rich, low-carb). Run in Supabase SQL Editor. Idempotent.

INSERT INTO public.recipes (id,title,subtitle,emoji,image_url,tags,meal,categories,diet,is_kids,prep_minutes,cook_minutes,servings,nutrition,ingredients,dressing,base_ingredients,steps,i18n) VALUES (
 'zucchini-noodle-pesto', 'Zucchini Noodle Spaghetti with Pesto & Feta', 'Fresh basil pesto, cherry tomatoes, feta & parmesan — protein-rich, low-carb "spaghetti"', '🥒', NULL,
 ARRAY['Vegetarian','Gluten-free','High-protein'], ARRAY['Main Course'], ARRAY['Pasta'], ARRAY['vegetarian','gluten-free'],
 false, 15, 5, 2,
 '{"kcal":480,"protein":20,"carbs":16,"fat":39,"fiber":4}'::jsonb, '[{"emoji":"🥒","name":"Zucchini (courgette), spiralized","amount":"3 medium (600g)"},{"emoji":"🍅","name":"Cherry tomatoes, halved","amount":"200g"},{"emoji":"🌿","name":"Fresh basil","amount":"40g"},{"emoji":"🧄","name":"Garlic","amount":"1 clove"},{"emoji":"🌰","name":"Pine nuts","amount":"30g"},{"emoji":"🧀","name":"Parmesan, grated","amount":"40g"},{"emoji":"🫒","name":"Extra-virgin olive oil","amount":"60ml"},{"emoji":"🍋","name":"Lemon","amount":"½"},{"emoji":"🧀","name":"Feta cheese, crumbled","amount":"120g"}]'::jsonb, NULL, '["Sea salt","Black pepper"]'::jsonb, '[{"title":"Spiralize the zucchini","text":"Spiralize the zucchini into long spaghetti-like strands. Pat them dry with a clean cloth and set aside.","ings":["🥒 Zucchini · 600g"]},{"title":"Make the pesto","text":"Blitz the basil, garlic, pine nuts, parmesan, olive oil, lemon juice and a pinch of salt into a smooth, loose pesto.","ings":["🌿 Fresh basil · 40g","🧄 Garlic · 1 clove","🌰 Pine nuts · 30g","🧀 Parmesan · 40g","🫒 Olive oil · 60ml","🍋 Lemon · ½"]},{"title":"Warm the noodles","text":"Toss the zucchini noodles in a hot dry pan for just 1–2 minutes to warm through — keep them al dente so they stay like spaghetti, not soggy. (Or skip for a fresh no-cook version.)","ings":[],"tip":"Don’t salt the zoodles early or overcook them — that’s what makes them watery."},{"title":"Toss with pesto & tomatoes","text":"Take off the heat and toss the noodles with the pesto and halved cherry tomatoes until everything is glossy and coated.","ings":["🍅 Cherry tomatoes · 200g"]},{"title":"Add feta & serve","text":"Twirl into nests, scatter over the crumbled feta for a protein boost, then top with a little extra parmesan, a few pine nuts and black pepper. Serve straight away.","ings":["🧀 Feta cheese · 120g"]}]'::jsonb, '{"de":{"title":"Zucchini-Nudel-Spaghetti mit Pesto & Feta","subtitle":"Frisches Basilikum-Pesto, Kirschtomaten, Feta & Parmesan — proteinreiche, kohlenhydratarme „Spaghetti\"","ingredients":["Zucchini, spiralisiert","Kirschtomaten, halbiert","Frisches Basilikum","Knoblauch","Pinienkerne","Parmesan, gerieben","Natives Olivenöl extra","Zitrone","Feta, zerbröselt"],"base":["Meersalz","Schwarzer Pfeffer"],"steps":[{"title":"Zucchini spiralisieren","text":"Die Zucchini zu langen, spaghettiartigen Streifen spiralisieren. Mit einem sauberen Tuch trocken tupfen und beiseitestellen.","ings":["🥒 Zucchini · 600g"]},{"title":"Pesto machen","text":"Basilikum, Knoblauch, Pinienkerne, Parmesan, Olivenöl, Zitronensaft und eine Prise Salz zu einem glatten, geschmeidigen Pesto mixen.","ings":["🌿 Frisches Basilikum · 40g","🧄 Knoblauch · 1 Zehe","🌰 Pinienkerne · 30g","🧀 Parmesan · 40g","🫒 Olivenöl · 60ml","🍋 Zitrone · ½"]},{"title":"Nudeln erwärmen","text":"Die Zucchininudeln in einer heißen, trockenen Pfanne nur 1–2 Minuten schwenken, damit sie warm werden — bissfest lassen, damit sie wie Spaghetti bleiben und nicht matschig werden. (Oder für die frische No-Cook-Variante weglassen.)","ings":[],"tip":"Die Zoodles nicht früh salzen und nicht zu lange garen — sonst werden sie wässrig."},{"title":"Mit Pesto & Tomaten schwenken","text":"Vom Herd nehmen und die Nudeln mit dem Pesto und den halbierten Kirschtomaten schwenken, bis alles glänzt und überzogen ist.","ings":["🍅 Kirschtomaten · 200g"]},{"title":"Feta dazu & servieren","text":"Zu Nestern drehen, den zerbröselten Feta als Protein-Boost darüberstreuen, dann mit etwas Parmesan, ein paar Pinienkernen und schwarzem Pfeffer toppen. Sofort servieren.","ings":["🧀 Feta · 120g"]}]},"fr":{"title":"Spaghettis de courgette au pesto & feta","subtitle":"Pesto de basilic frais, tomates cerises, feta & parmesan — des « spaghettis » riches en protéines et pauvres en glucides","ingredients":["Courgettes, en spirales","Tomates cerises, coupées en deux","Basilic frais","Ail","Pignons de pin","Parmesan, râpé","Huile d’olive vierge extra","Citron","Feta, émietté"],"base":["Sel de mer","Poivre noir"],"steps":[{"title":"Passer les courgettes au spiraliseur","text":"Transforme les courgettes en longues lanières façon spaghettis. Éponge-les avec un linge propre et réserve.","ings":["🥒 Courgette · 600g"]},{"title":"Préparer le pesto","text":"Mixe le basilic, l’ail, les pignons, le parmesan, l’huile d’olive, le jus de citron et une pincée de sel en un pesto lisse et souple.","ings":["🌿 Basilic frais · 40g","🧄 Ail · 1 gousse","🌰 Pignons de pin · 30g","🧀 Parmesan · 40g","🫒 Huile d’olive · 60ml","🍋 Citron · ½"]},{"title":"Réchauffer les nouilles","text":"Fais sauter les nouilles de courgette dans une poêle chaude et sèche 1 à 2 minutes juste pour les réchauffer — garde-les al dente pour qu’elles restent comme des spaghettis. (Ou saute cette étape pour une version crue.)","ings":[],"tip":"Ne sale pas les courgettes trop tôt et ne les surcuis pas — c’est ce qui les rend aqueuses."},{"title":"Mélanger avec le pesto & les tomates","text":"Hors du feu, mélange les nouilles avec le pesto et les tomates cerises coupées jusqu’à ce que tout soit brillant et enrobé.","ings":["🍅 Tomates cerises · 200g"]},{"title":"Ajouter la feta & servir","text":"Forme des nids, parsème de feta émiettée pour un apport en protéines, puis ajoute un peu de parmesan, quelques pignons et du poivre noir. Sers aussitôt.","ings":["🧀 Feta · 120g"]}]},"es":{"title":"Espaguetis de calabacín con pesto y feta","subtitle":"Pesto de albahaca fresca, tomates cherry, feta y parmesano — unos «espaguetis» ricos en proteína y bajos en carbohidratos","ingredients":["Calabacín, en espiral","Tomates cherry, cortados por la mitad","Albahaca fresca","Ajo","Piñones","Parmesano, rallado","Aceite de oliva virgen extra","Limón","Feta, desmenuzado"],"base":["Sal marina","Pimienta negra"],"steps":[{"title":"Espiralizar el calabacín","text":"Convierte el calabacín en tiras largas tipo espagueti. Sécalas con un paño limpio y reserva.","ings":["🥒 Calabacín · 600g"]},{"title":"Hacer el pesto","text":"Tritura la albahaca, el ajo, los piñones, el parmesano, el aceite de oliva, el zumo de limón y una pizca de sal hasta lograr un pesto suave y fluido.","ings":["🌿 Albahaca fresca · 40g","🧄 Ajo · 1 diente","🌰 Piñones · 30g","🧀 Parmesano · 40g","🫒 Aceite de oliva · 60ml","🍋 Limón · ½"]},{"title":"Calentar los fideos","text":"Saltea los fideos de calabacín en una sartén caliente y seca solo 1–2 minutos para templarlos — déjalos al dente para que sigan como espaguetis y no queden blandos. (O sáltate el paso para una versión sin cocción.)","ings":[],"tip":"No sales el calabacín pronto ni lo cocines de más — eso es lo que lo vuelve aguado."},{"title":"Mezclar con pesto y tomates","text":"Fuera del fuego, mezcla los fideos con el pesto y los tomates cherry hasta que todo quede brillante y cubierto.","ings":["🍅 Tomates cherry · 200g"]},{"title":"Añadir feta y servir","text":"Forma nidos, esparce la feta desmenuzada para un extra de proteína, luego corona con un poco de parmesano, unos piñones y pimienta negra. Sirve enseguida.","ings":["🧀 Feta · 120g"]}]}}'::jsonb
)
